// ===================================================================
// Auto-generated Multi-Channel Image Filter
// ===================================================================
module complex_image_filter_design702 (
    input clk,

    // ===================================================================
    // Channel 1 : 45-bit + 45-bit adder
    // ===================================================================
    input signed [44:0] ch1_a,
    input signed [44:0] ch1_b,

    // ===================================================================
    // Channel 2 (保持原逻辑)
    // ===================================================================
    input signed [14:0] pix2,
    input signed [16:0] k2a,
    input signed [11:0] k2b,
    input signed [9:0]  k2c,

    // ===================================================================
    // Channel 3 (保持原逻辑)
    // ===================================================================
    input signed [8:0]  pix3,
    input signed [14:0] k3a,
    input signed [9:0]  k3b,
    input signed [7:0]  k3c,

    // ===================================================================
    // Channel 4 : 43-bit + 43-bit adder
    // ===================================================================
    input signed [42:0] ch4_a,
    input signed [42:0] ch4_b,

    // ===================================================================
    // Channel 5 (保持原逻辑)
    // ===================================================================
    input signed [14:0] pix5,
    input signed [10:0] k5a,
    input signed [12:0] k5b,
    input signed [16:0] k5c,

    // ===================================================================
    // Final Output (最大位宽，不截断)
    // ===================================================================
    output signed [45:0] final_out
);

    // ===================================================================
    // Channel outputs
    // ===================================================================
    wire signed [45:0] channel1_out;  // 45+45
    wire signed [30:0] channel2_out;
    wire signed [26:0] channel3_out;
    wire signed [43:0] channel4_out;  // 43+43
    wire signed [17:0] channel5_out;

    // ===================================================================
    // Channel 1 : 45-bit combinational add
    // ===================================================================
    assign channel1_out = ch1_a + ch1_b;

    // ===================================================================
    // Channel 2 : 原逻辑保持
    // ===================================================================
    logic signed [30:0] stage0_ch2;
    always @(posedge clk) begin
        stage0_ch2 <= ((k2a + pix2) * k2b) + k2c;
    end
    assign channel2_out = stage0_ch2;

    // ===================================================================
    // Channel 3 : 原逻辑保持
    // ===================================================================
    logic signed [26:0] stage0_ch3, stage1_ch3;
    always @(posedge clk) begin
        stage0_ch3 <= ((k3a + pix3) * k3b) + k3c;
        stage1_ch3 <= stage0_ch3;
    end
    assign channel3_out = stage1_ch3;

    // ===================================================================
    // Channel 4 : 43-bit combinational add
    // ===================================================================
    assign channel4_out = ch4_a + ch4_b;

    // ===================================================================
    // Channel 5 : 原逻辑保持
    // ===================================================================
    logic signed [17:0] stage0_ch5;
    always @(posedge clk) begin
        stage0_ch5 <= ((k5a + pix5) * k5b) & k5c;
    end
    assign channel5_out = stage0_ch5;

    // ===================================================================
    // Output Combination
    // 统一符号扩展到 46 bits（最大位宽）
    // ===================================================================
    assign final_out =
        channel1_out +                                   // 46
        { {15{channel2_out[30]}}, channel2_out } +       // 31 → 46
        { {19{channel3_out[26]}}, channel3_out } +       // 27 → 46
        { {2{channel4_out[43]}},  channel4_out } +       // 44 → 46
        { {28{channel5_out[17]}}, channel5_out };        // 18 → 46

endmodule
